using Microsoft.EntityFrameworkCore;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: EF 9 renamed the discriminator JSON property from
        // "Discriminator" to "$type". Existing documents and raw SQL queries
        // (e.g. WHERE c.Discriminator = 'Blog') use the old name.
        modelBuilder.Entity<Blog>()
            .Property("Discriminator")
            .ToJsonProperty("Discriminator");

        // Breaking change #2: EF 9 no longer includes the discriminator in the
        // Cosmos "id" value. Old format was "Blog|1", new format is just "1".
        // Restore old behavior so existing documents remain accessible.
        modelBuilder.HasDiscriminatorInJsonIds();

        // Breaking change #3: HasIndex() now throws InvalidOperationException for
        // Cosmos entities (Cosmos manages indexes server-side).
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

