using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 renamed "Discriminator" to "$type".
            // Existing documents use "Discriminator", so preserve the old property name.
            entity.HasDiscriminator().HasJsonPropertyName("Discriminator");

            // Breaking change 2: EF 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents use "Blog|1" format, so opt back in to the legacy format.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                  .HasJsonPropertyName("id")
                  .ToJsonProperty("id");

            // Breaking change 3: Cosmos DB does not support indexes defined via EF Core.
            // HasIndex() now throws by default in EF 9. Remove it entirely.
            // (HasIndex call removed below)
        });
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // Breaking change 2 fix: Restore the legacy "EntityType|Key" id format
        // so existing documents with id "Blog|1" remain accessible.
        configurationBuilder.Conventions.Add(_ =>
            new Microsoft.EntityFrameworkCore.Cosmos.Infrastructure.IdValueGeneratorConvention());
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

